const book: BibleBook = {
  id: 'amos',
  name: 'Amós',
  englishName: 'Amos',
  testament: 'old',
  chapters: {
    1: [
      { v: 1, en: 'The words of Amos, who was among the herdsmen of Tekoa, which he saw concerning Israel in the days of Uzziah king of Judah, and in the days of Jeroboam the son of Joash king of Israel, two years before the earthquake.', pt: 'As palavras de Amós, que estava entre os pastores de Tecoa, o que ele viu a respeito de Israel, nos dias de Uzias, rei de Judá, e nos dias de Jeroboão, filho de Joás, rei de Israel, dois anos antes do terremoto.' },
      { v: 2, en: 'He said: “Yahweh will roar from Zion, and utter his voice from Jerusalem; and the pastures of the shepherds will mourn, and the top of Carmel will wither.”', pt: 'Disse ele: O Senhor brama de Sião, e de Jerusalém faz ouvir a sua voz; os prados dos pastores lamentam, seca-se o cume do Carmelo.' },
      { v: 3, en: 'Yahweh says: “For three transgressions of Damascus, yes, for four, I will not turn away its punishment; because they have threshed Gilead with threshing instruments of iron;', pt: 'Assim diz o senhor: Por três transgressões de Damasco, sim, por quatro, não retirarei o castigo; porque trilharam a Gileade com trilhos de ferro.' },
      { v: 4, en: 'but I will send a fire into the house of Hazael, and it will devour the palaces of Ben Hadad.', pt: 'Por isso porei fogo à casa de Hazael, e ele consumirá os palácios de Bene-Hadade.' },
      { v: 5, en: 'I will break the bar of Damascus, and cut off the inhabitant from the valley of Aven, and him who holds the scepter from the house of Eden; and the people of Syria shall go into captivity to Kir,” says Yahweh.', pt: 'Quebrarei o ferrolho de Damasco, e exterminarei o morador do vale de Ávem e de Bete-Éden aquele que tem o cetro; e o povo da Síria será levado em cativeiro a Quir, diz o Senhor.' },
      { v: 6, en: 'Yahweh says: “For three transgressions of Gaza, yes, for four, I will not turn away its punishment; because they carried away captive the whole community, to deliver them up to Edom;', pt: 'Assim diz o Senhor: Por três transgressões de Gaza, sim, por quatro, não retirarei o castigo; porque levaram cativo todo o povo para o entregarem a Edom.' },
      { v: 7, en: 'but I will send a fire on the wall of Gaza, and it will devour its palaces.', pt: 'Por isso porei fogo ao muro de Gaza, e ele consumirá os seus palácios.' },
      { v: 8, en: 'I will cut off the inhabitant from Ashdod, and him who holds the scepter from Ashkelon; and I will turn my hand against Ekron; and the remnant of the Philistines will perish,” says the Lord Yahweh.', pt: 'De Asdode exterminarei o morador, e de Asquelom aquele que tem o cetro; tornarei a minha mão contra Ecrom; e o resto dos filisteus perecerá, diz o Senhor Deus.' },
      { v: 9, en: 'Yahweh says: “For three transgressions of Tyre, yes, for four, I will not turn away its punishment; because they delivered up the whole community to Edom, and didn’t remember the brotherly covenant;', pt: 'Assim diz o Senhor: Por três transgressões de Tiro, sim, por quatro, não retirarei o castigo; porque entregaram todos os cativos a Edom, e não se lembraram da aliança dos irmãos.' },
      { v: 10, en: 'but I will send a fire on the wall of Tyre, and it will devour its palaces.”', pt: 'por isso porei fogo ao muro de Tiro, e ele consumirá os seus palácios.' },
      { v: 11, en: 'Yahweh says: “For three transgressions of Edom, yes, for four, I will not turn away its punishment; because he pursued his brother with the sword, and cast off all pity, and his anger raged continually, and he kept his wrath forever;', pt: 'Assim diz o Senhor: Por três transgressões de Edom, sim, por quatro, não retirarei o castigo; porque perseguiu a seu irmão à espada, e baniu toda a compaixão; e a sua ira despedaçou eternamente, e conservou a sua indignação para sempre.' },
      { v: 12, en: 'but I will send a fire on Teman, and it will devour the palaces of Bozrah.”', pt: 'Por isso porei fogo a Temã, o qual consumirá os palácios de Bozra.' },
      { v: 13, en: 'Yahweh says: “For three transgressions of the children of Ammon, yes, for four, I will not turn away its punishment; because they have ripped open the pregnant women of Gilead, that they may enlarge their border.', pt: 'Assim diz o Senhor: Por três transgressões dos filhos de Amom, sim por quatro, não retirarei o castigo; porque fenderam o ventre às grávidas de Gileade, para dilatarem os seus termos.' },
      { v: 14, en: 'But I will kindle a fire in the wall of Rabbah, and it will devour its palaces, with shouting in the day of battle, with a storm in the day of the whirlwind;', pt: 'Por isso porei fogo ao muro de Rabá, fogo que lhe consumirá os palácios, com alarido no dia da batalha, com tempestade no dia do turbilhão.' },
      { v: 15, en: 'and their king will go into captivity, he and his princes together,” says Yahweh.', pt: 'E o seu rei irá para o cativeiro, ele e os seus príncipes juntamente, diz o Senhor.' },
    ],
    2: [
      { v: 1, en: 'Yahweh says: “For three transgressions of Moab, yes, for four, I will not turn away its punishment; because he burned the bones of the king of Edom into lime;', pt: 'Assim diz o Senhor: Por três transgressões de Moabe, sim, por quatro, não retirarei o castigo; porque queimou os ossos do rei de Edom, até os reduzir a cal.' },
      { v: 2, en: 'but I will send a fire on Moab, and it will devour the palaces of Kerioth; and Moab will die with tumult, with shouting, and with the sound of the trumpet;', pt: 'Por isso porei fogo a Moabe, e ele consumirá os palácios de Queriote; e Moabe morrerá com grande estrondo, com alarido, e som de trombeta.' },
      { v: 3, en: 'and I will cut off the judge from among them, and will kill all its princes with him,” says Yahweh.', pt: 'E exterminarei o juiz do meio dele, e matarei com ele todos os seus príncipes, diz o Senhor.' },
      { v: 4, en: 'Yahweh says: “For three transgressions of Judah, yes, for four, I will not turn away its punishment; because they have rejected Yahweh’s law, and have not kept his statutes, and their lies have led them astray, after which their fathers walked;', pt: 'Assim diz o Senhor: Por três transgressoes de Judá, sim, por quatro, não retirarei o castigo; porque rejeitaram a lei do Senhor, e não guardaram os seus estatutos, antes se deixaram enganar por suas próprias mentiras, após as quais andaram seus pais.' },
      { v: 5, en: 'but I will send a fire on Judah, and it will devour the palaces of Jerusalem.”', pt: 'Por isso porei fogo a Judá, e ele consumirá os palácios de Jerusalém.' },
      { v: 6, en: 'Yahweh says: “For three transgressions of Israel, yes, for four, I will not turn away its punishment; because they have sold the righteous for silver, and the needy for a pair of shoes;', pt: 'Assim diz o Senhor: Por três transgressões de Israel, sim, por quatro, não retirarei o castigo; porque vendem o justo por dinheiro, e o necessitado por um par de sapatos.' },
      { v: 7, en: 'They trample on the dust of the earth on the head of the poor, and deny justice to the oppressed; and a man and his father use the same maiden, to profane my holy name;', pt: 'Pisam a cabeça dos pobres no pó da terra, pervertem o caminho dos mansos; um homem e seu pai entram à mesma moça, assim profanando o meu santo nome.' },
      { v: 8, en: 'and they lay themselves down beside every altar on clothes taken in pledge; and in the house of their God they drink the wine of those who have been fined.', pt: 'Também se deitam junto a qualquer altar sobre roupas empenhadas, e na casa de seu Deus bebem o vinho dos que têm sido multados.' },
      { v: 9, en: 'Yet I destroyed the Amorite before them, whose height was like the height of the cedars, and he was strong as the oaks; yet I destroyed his fruit from above, and his roots from beneath.', pt: 'Contudo eu destruí o amorreu diante deles, a altura do qual era como a dos cedros, e cuja força era como a dos carvalhos; mas destruí o seu fruto por cima, e as suas raízes por baixo.' },
      { v: 10, en: 'Also I brought you up out of the land of Egypt, and led you forty years in the wilderness, to possess the land of the Amorite.', pt: 'Outrossim vos fiz subir da terra do Egito, e quarenta anos vos guiei no deserto, para que possuísseis a terra do amorreu.' },
      { v: 11, en: 'I raised up some of your sons for prophets, and some of your young men for Nazirites. Isn’t this true, you children of Israel?” says Yahweh.', pt: 'E dentre vossos filhos suscitei profetas, e dentre os vossos mancebos, nazireus. Acaso não é isso assim, filhos de Israel? diz o Senhor.' },
      { v: 12, en: '“But you gave the Nazirites wine to drink, and commanded the prophets, saying, ‘Don’t prophesy!’', pt: 'Mas vós aos nazireus destes vinho a beber, e aos profetas ordenastes, dizendo: Não profetizeis.' },
      { v: 13, en: 'Behold, I will crush you in your place, as a cart crushes that is full of grain.', pt: 'Eis que eu vos apertarei no vosso lugar como se aperta um carro cheio de feixes.' },
      { v: 14, en: 'Flight will perish from the swift; and the strong won’t strengthen his force; neither shall the mighty deliver himself;', pt: 'Assim de nada valerá a fuga ao ágil, nem o forte corroborará a sua força, nem o valente salvará a sua vida.' },
      { v: 15, en: 'neither shall he stand who handles the bow; and he who is swift of foot won’t escape; neither shall he who rides the horse deliver himself;', pt: 'E não ficará em pé o que maneja o arco, nem o ligeiro de pés se livrará, nem tampouco se livrara o que vai montado a cavalo;' },
      { v: 16, en: 'and he who is courageous among the mighty will flee away naked on that day,” says Yahweh.', pt: 'e aquele que é corajoso entre os valentes fugirá nu naquele dia, diz o Senhor.' },
    ],
    3: [
      { v: 1, en: 'Hear this word that Yahweh has spoken against you, children of Israel, against the whole family which I brought up out of the land of Egypt, saying:', pt: 'Ouvi esta palavra que o Senhor fala contra vós, filhos de Israel, contra toda a família que fiz subir da terra do Egito, dizendo:' },
      { v: 2, en: '“I have only chosen you of all the families of the earth. Therefore I will punish you for all of your sins.”', pt: 'De todas as famílias da terra só a vós vos tenho conhecido; portanto eu vos punirei por todas as vossas iniqüidades.' },
      { v: 3, en: 'Do two walk together, unless they have agreed?', pt: 'Acaso andarão dois juntos, se não estiverem de acordo?' },
      { v: 4, en: 'Will a lion roar in the thicket, when he has no prey? Does a young lion cry out of his den, if he has caught nothing?', pt: 'Bramirá o leão no bosque, sem que tenha presa? Fará ouvir a sua voz o leão novo no seu covil, se nada tiver apanhado?' },
      { v: 5, en: 'Can a bird fall in a trap on the earth, where no snare is set for him? Does a snare spring up from the ground, when there is nothing to catch?', pt: 'Cairá a ave no laço em terra, se não houver armadilha para ela? levantar-se-á da terra o laço, sem que tenha apanhado alguma coisa?' },
      { v: 6, en: 'Does the trumpet alarm sound in a city, without the people being afraid? Does evil happen to a city, and Yahweh hasn’t done it?', pt: 'Tocar-se-á a trombeta na cidade, e o povo não estremecerá? Sucederá qualquer mal à cidade, sem que o Senhor o tenha feito?' },
      { v: 7, en: 'Surely the Lord Yahweh will do nothing, unless he reveals his secret to his servants the prophets.', pt: 'Certamente o Senhor Deus não fará coisa alguma, sem ter revelado o seu segredo aos seus servos, os profetas.' },
      { v: 8, en: 'The lion has roared. Who will not fear? The Lord Yahweh has spoken. Who can but prophesy?', pt: 'Bramiu o leão, quem não temerá? Falou o Senhor Deus, quem não profetizará?' },
      { v: 9, en: 'Proclaim in the palaces at Ashdod, and in the palaces in the land of Egypt, and say, “Assemble yourselves on the mountains of Samaria, and see what unrest is in her, and what oppression is among them.”', pt: 'Proclamai nos palácios de Asdode, e nos palácios da terra do Egito, e dizei: Ajuntai-vos sobre os montes de Samária, e vede que grandes alvoroços nela há, e que opressões no meio dela.' },
      { v: 10, en: '“Indeed they don’t know to do right,” says Yahweh, “Who hoard plunder and loot in their palaces.”', pt: 'Pois não sabem fazer o que é reto, diz o Senhor, aqueles que entesouram nos seus palácios a violência e a destruição.' },
      { v: 11, en: 'Therefore thus says the Lord Yahweh: “An adversary will overrun the land; and he will pull down your strongholds, and your fortresses will be plundered.”', pt: 'Portanto, o Senhor Deus diz assim: um inimigo cercará a tua terra; derrubará a tua fortaleza, e os teus palácios serão saqueados.' },
      { v: 12, en: 'Yahweh says: “As the shepherd rescues out of the mouth of the lion two legs, or a piece of an ear, so shall the children of Israel be rescued who sit in Samaria on the corner of a couch, and on the silken cushions of a bed.”', pt: 'Assim diz o Senhor: Como o pastor livra da boca do leão as duas pernas, ou um pedacinho da orelha, assim serão livrados os filhos de Israel que habitam em Samária, junto com um canto do leito e um pedaço da cama.' },
      { v: 13, en: '“Listen, and testify against the house of Jacob,” says the Lord Yahweh, the God of Armies.', pt: 'Ouvi, e protestai contra a casa de Jacó, diz o Senhor Deus, o Deus dos exércitos:' },
      { v: 14, en: '“For in the day that I visit the transgressions of Israel on him, I will also visit the altars of Bethel; and the horns of the altar will be cut off, and fall to the ground.', pt: 'Pois no dia em que eu punir as transgressões de Israel, também castigarei os altares de Betel; e as pontas do altar serão cortadas, e cairão por terra.' },
      { v: 15, en: 'I will strike the winter house with the summer house; and the houses of ivory will perish, and the great houses will have an end,” says Yahweh.', pt: 'Derribarei a casa de inverno juntamente com a casa de verão; as casas de marfim perecerão, e as grandes casas terão fim, diz o Senhor.' },
    ],
    4: [
      { v: 1, en: 'Listen to this word, you cows of Bashan, who are on the mountain of Samaria, who oppress the poor, who crush the needy, who tell their husbands, “Bring us drinks!”', pt: 'Ouvi esta palavra, vós, vacas de Basã, que estais no monte de Samária, que oprimis os pobres, que esmagais os necessitados, que dizeis a vossos maridos: Dai cá, e bebamos.' },
      { v: 2, en: 'The Lord Yahweh has sworn by his holiness that behold, “The days shall come on you that they will take you away with hooks, and the last of you with fish hooks.', pt: 'Jurou o Senhor Deus, pela sua santidade, que dias estão para vir sobre vós, em que vos levarão com anzóis, e aos que sairdes por último com anzóis de pesca.' },
      { v: 3, en: 'You will go out at the breaks in the wall, everyone straight before her; and you will cast yourselves into Harmon,” says Yahweh.', pt: 'E saireis pelas brechas, cada qual em frente de si, e sereis lançadas para Harmom, diz o senhor.' },
      { v: 4, en: '“Go to Bethel, and sin; to Gilgal, and sin more. Bring your sacrifices every morning, your tithes every three days,', pt: 'Vinde a Betel, e transgredi; a Gilgal, e multiplicai as transgressões; e cada manhã trazei os vossos sacrifícios, e de três em três dias os vossos dízimos.' },
      { v: 5, en: 'offer a sacrifice of thanksgiving of that which is leavened, and proclaim free will offerings and brag about them: for this pleases you, you children of Israel,” says the Lord Yahweh.', pt: 'E oferecei sacrifício de louvores do que é levedado, e apregoai ofertas voluntárias, publicai-as; pois disso gostais, ó filhos de Israel, diz o Senhor Deus.' },
      { v: 6, en: '“I also have given you cleanness of teeth in all your cities, and lack of bread in every town; yet you haven’t returned to me,” says Yahweh.', pt: 'Por isso também vos dei limpeza de dentes em todas as vossas cidades, e falta de pão em todos os vossos lugares; contudo não vos convertestes a mim, diz o Senhor.' },
      { v: 7, en: '“I also have withheld the rain from you, when there were yet three months to the harvest; and I caused it to rain on one city, and caused it not to rain on another city. One place was rained on, and the piece where it didn’t rain withered.', pt: 'Além disso, retive de vós a chuva, quando ainda faltavam três meses para a ceifa; e fiz que chovesse sobre uma cidade, e que não chovesse sobre outra cidade; sobre um campo choveu, mas o outro, sobre o qual não choveu, secou-se.' },
      { v: 8, en: 'So two or three cities staggered to one city to drink water, and were not satisfied: yet you haven’t returned to me,” says Yahweh.', pt: 'Andaram errantes duas ou três cidades, indo a outra cidade para beberem água, mas não se saciaram; contudo não vos convertestes a mim, diz o Senhor.' },
      { v: 9, en: '“I struck you with blight and mildew many times in your gardens and your vineyards; and your fig trees and your olive trees have the swarming locust devoured: yet you haven’t returned to me,” says Yahweh.', pt: 'Feri-vos com crestamento e ferrugem; a multidão das vossas hortas, e das vossas vinhas, e das vossas figueiras, e das vossas oliveiras, foi devorada pela locusta; contudo não vos convertestes a mim, diz o Senhor.' },
      { v: 10, en: '“I sent plagues among you like I did Egypt. I have slain your young men with the sword, and have carried away your horses; and I filled your nostrils with the stench of your camp, yet you haven’t returned to me,” says Yahweh.', pt: 'Enviei a peste contra vós, à maneira de Egito; os vossos mancebos matei à espada, e os vossos cavalos deixei levar presos, e o fedor do vosso arraial fiz subir aos vossos narizes; contudo não vos convertestes a mim, diz o Senhor.' },
      { v: 11, en: '“I have overthrown some of you, as when God overthrew Sodom and Gomorrah, and you were like a burning stick plucked out of the fire; yet you haven’t returned to me,” says Yahweh.', pt: 'Subverti alguns dentre vós, como Deus subverteu a Sodoma e Gomorra, e ficastes sendo como um tição arrebatado do incêndio; contudo não vos convertestes a mim, diz o Senhor.' },
      { v: 12, en: '“Therefore thus will I do to you, Israel; because I will do this to you, prepare to meet your God, Israel.', pt: 'Portanto assim te farei, ó Israel, e porque isso te farei, prepara-te, ó Israel, para te encontrares com o teu Deus.' },
      { v: 13, en: 'For, behold, he who forms the mountains, and creates the wind, and declares to man what is his thought; who makes the morning darkness, and treads on the high places of the earth: Yahweh, the God of Armies, is his name.”', pt: 'Porque é ele o que forma os montes, e cria o vento, e declara ao homem qual seja o seu pensamento, o que faz da manhã trevas, e anda sobre os lugares altos da terra; o Senhor, o Deus dos exércitos é o seu nome.' },
    ],
    5: [
      { v: 1, en: 'Listen to this word which I take up for a lamentation over you, O house of Israel.', pt: 'Ouvi esta palavra que levanto como lamentação sobre vós, ó casa de Israel.' },
      { v: 2, en: '“The virgin of Israel has fallen; She shall rise no more. She is cast down on her land; there is no one to raise her up.”', pt: 'A virgem de Israel caiu; nunca mais tornará a levantar-se; desamparada jaz na sua terra; não há quem a levante.' },
      { v: 3, en: 'For thus says the Lord Yahweh: “The city that went out a thousand shall have a hundred left, and that which went out one hundred shall have ten left to the house of Israel.”', pt: 'Porque assim diz o Senhor Deus: A cidade da qual saem mil terá de resto cem, e aquela da qual saem cem terá dez para a casa de Israel.' },
      { v: 4, en: 'For Yahweh says to the house of Israel: “Seek me, and you will live;', pt: 'Pois assim diz o Senhor à casa de Israel: Buscai-me, e vivei.' },
      { v: 5, en: 'but don’t seek Bethel, nor enter into Gilgal, and don’t pass to Beersheba: for Gilgal shall surely go into captivity, and Bethel shall come to nothing.', pt: 'Mas não busqueis a Betel, nem entreis em Gilgal, nem passeis a Berseba; porque Gilgal certamente irá ao cativeiro, e Betel será desfeita em nada.' },
      { v: 6, en: 'Seek Yahweh, and you will live; lest he break out like fire in the house of Joseph, and it devour, and there be no one to quench it in Bethel.', pt: 'Buscai ao Senhor, e vivei; para que ele não irrompa na casa de José como fogo e a consuma, e não haja em Betel quem o apague.' },
      { v: 7, en: 'You who turn justice to wormwood, and cast down righteousness to the earth:', pt: 'Vós que converteis o juízo em alosna, e deitais por terra a justiça,' },
      { v: 8, en: 'seek him who made the Pleiades and Orion, and turns the shadow of death into the morning, and makes the day dark with night; who calls for the waters of the sea, and pours them out on the surface of the earth, Yahweh is his name,', pt: 'procurai aquele que fez as Plêiades e o Oriom, e torna a sombra da noite em manhã, e transforma o dia em noite; o que chama as águas do mar, e as derrama sobre a terra; o Senhor é o seu nome.' },
      { v: 9, en: 'who brings sudden destruction on the strong, so that destruction comes on the fortress.', pt: 'O que faz vir súbita destruição sobre o forte, de sorte que vem a ruína sobre a fortaleza.' },
      { v: 10, en: 'They hate him who reproves in the gate, and they abhor him who speaks blamelessly.', pt: 'Eles odeiam ao que na porta os repreende, e abominam ao que fala a verdade.' },
      { v: 11, en: 'Therefore, because you trample on the poor, and take taxes from him of wheat: You have built houses of cut stone, but you will not dwell in them. You have planted pleasant vineyards, but you shall not drink their wine.', pt: 'Portanto, visto que pisais o pobre, e dele exigis tributo de trigo, embora tenhais edificado casas de pedras lavradas, não habitareis nelas; e embora tenhais plantado vinhas desejáveis, não bebereis do seu vinho.' },
      { v: 12, en: 'For I know how many your offenses, and how great are your sins— you who afflict the just, who take a bribe, and who turn away the needy in the courts.', pt: 'Pois sei que são muitas as vossas transgressões, e graves os vossos pecados; afligis o justo, aceitais peitas, e na porta negais o direito aos necessitados.' },
      { v: 13, en: 'Therefore a prudent person keeps silent in such a time, for it is an evil time.', pt: 'Portanto, o que for prudente guardará silêncio naquele tempo, porque o tempo será mau.' },
      { v: 14, en: 'Seek good, and not evil, that you may live; and so Yahweh, the God of Armies, will be with you, as you say.', pt: 'Buscai o bem, e não o mal, para que vivais; e assim o Senhor, o Deus dos exércitos, estará convosco, como dizeis.' },
      { v: 15, en: 'Hate evil, love good, and establish justice in the courts. It may be that Yahweh, the God of Armies, will be gracious to the remnant of Joseph.”', pt: 'Aborrecei o mal, e amai o bem, e estabelecei o juízo na porta. Talvez o Senhor, o Deus dos exércitos, tenha piedade do resto de José.' },
      { v: 16, en: 'Therefore Yahweh, the God of Armies, the Lord, says: “Wailing will be in all the wide ways; and they will say in all the streets, ‘Alas! Alas!’ and they will call the farmer to mourning, and those who are skillful in lamentation to wailing.', pt: 'Portanto, assim diz o Senhor Deus dos exércitos, o Senhor: Em todas as praças haverá pranto, e em todas as ruas dirão: Ai! ai! E ao lavrador chamarão para choro, e para pranto os que souberem prantear.' },
      { v: 17, en: 'In all vineyards there will be wailing; for I will pass through the middle of you,” says Yahweh.', pt: 'E em todas as vinhas haverá pranto; porque passarei pelo meio de ti, diz o Senhor.' },
      { v: 18, en: '“Woe to you who desire the day of Yahweh! Why do you long for the day of Yahweh? It is darkness, and not light.', pt: 'Ai de vós que desejais o dia do Senhor! Para que quereis vós este dia do Senhor? Ele é trevas e não luz.' },
      { v: 19, en: 'As if a man fled from a lion, and a bear met him; Or he went into the house and leaned his hand on the wall, and a snake bit him.', pt: 'E como se um homem fugisse de diante do leão, e se encontrasse com ele o urso; ou como se, entrando em casa, encostasse a mão à parede, e o mordesse uma cobra.' },
      { v: 20, en: 'Won’t the day of Yahweh be darkness, and not light? Even very dark, and no brightness in it?', pt: 'Não será, pois, o dia do Senhor trevas e não luz? não será completa escuridade, sem nenhum resplendor?' },
      { v: 21, en: 'I hate, I despise your feasts, and I can’t stand your solemn assemblies.', pt: 'Aborreço, desprezo as vossas festas, e não me deleito nas vossas assembléias solenes.' },
      { v: 22, en: 'Yes, though you offer me your burnt offerings and meal offerings, I will not accept them; neither will I regard the peace offerings of your fat animals.', pt: 'Ainda que me ofereçais holocaustos, juntamente com as vossas ofertas de cereais, não me agradarei deles; nem atentarei para as ofertas pacíficas de vossos animais cevados.' },
      { v: 23, en: 'Take away from me the noise of your songs! I will not listen to the music of your harps.', pt: 'Afasta de mim o estrépito dos teus cânticos, porque não ouvirei as melodias das tuas liras.' },
      { v: 24, en: 'But let justice roll on like rivers, and righteousness like a mighty stream.', pt: 'Corra, porém, a justiça como as águas, e a retidão como o ribeiro perene.' },
      { v: 25, en: '“Did you bring to me sacrifices and offerings in the wilderness forty years, house of Israel?', pt: 'Oferecestes-me vós sacrifícios e oblações no deserto por quarenta anos, ó casa de Israel?' },
      { v: 26, en: 'You also carried the tent of your king and the shrine of your images, the star of your god, which you made for yourselves.', pt: 'Sim, levastes Sicute, vosso rei, e Quium, vosso deus-estrela, imagens que fizestes para vos mesmos.' },
      { v: 27, en: 'Therefore will I cause you to go into captivity beyond Damascus,” says Yahweh, whose name is the God of Armies.', pt: 'Portanto vos levarei cativos para além de Damasco, diz o Senhor, cujo nome é o Deus dos exércitos.' },
    ],
    6: [
      { v: 1, en: 'Woe to those who are at ease in Zion, and to those who are secure on the mountain of Samaria, the notable men of the chief of the nations, to whom the house of Israel come!', pt: 'Ai dos que vivem sossegados em Sião, e dos que estão seguros no monte de Samária, dos homens notáveis da principal das nações, e aos quais vem a casa de Israel!' },
      { v: 2, en: 'Go to Calneh, and see; and from there go to Hamath the great; then go down to Gath of the Philistines. are they better than these kingdoms? or is their border greater than your border?', pt: 'Passai a Calné, e vede; e dali ide à grande Hamate; depois descei a Gate dos filisteus; porventura são melhores que estes reinos? ou são maiores os seus termos do que os vossos termos?' },
      { v: 3, en: 'Those who put far away the evil day, and cause the seat of violence to come near;', pt: 'ó vós que afastais o dia mau e fazeis que se aproxime o assento da violência.' },
      { v: 4, en: 'Who lie on beds of ivory, and stretch themselves on their couches, and eat the lambs out of the flock, and the calves out of the middle of the stall;', pt: 'Ai dos que dormem em camas de marfim, e se estendem sobre os seus leitos, e comem os cordeiros tirados do rebanho, e os bezerros do meio do curral;' },
      { v: 5, en: 'who strum on the strings of a harp; who invent for themselves instruments of music, like David;', pt: 'que garganteiam ao som da lira, e inventam para si instrumentos músicos, assim como Davi;' },
      { v: 6, en: 'who drink wine in bowls, and anoint themselves with the best oils; but they are not grieved for the affliction of Joseph.', pt: 'que bebem vinho em taças, e se ungem com o mais excelente óleo; mas não se afligem por causa da ruína de José!' },
      { v: 7, en: 'Therefore they will now go captive with the first who go captive; and the feasting and lounging will end.', pt: 'Portanto agora irão em cativeiro entre os primeiros que forem cativos; e cessarão os festins dos banqueteadores.' },
      { v: 8, en: '“The Lord Yahweh has sworn by himself,” says Yahweh, the God of Armies: “I abhor the pride of Jacob, and detest his fortresses. Therefore I will deliver up the city with all that is in it.', pt: 'Jurou o Senhor Deus por si mesmo, diz o Senhor Deus dos exércitos: Abomino a soberba de Jacó, e odeio os seus palácios; por isso entregarei a cidade e tudo o que nela há.' },
      { v: 9, en: 'It will happen, if there remain ten men in one house, that they shall die.', pt: 'E se ficarem de resto dez homens numa casa, morrerão.' },
      { v: 10, en: '“When a man’s relative carries him, even he who burns him, to bring bodies out of the house, and asks him who is in the innermost parts of the house, ‘Is there yet any with you?’ And he says, ‘No;’ then he will say, ‘Hush! Indeed we must not mention Yahweh’s name.’', pt: 'Quando o parente de alguém, aquele que o queima, o tomar para levar-lhe os ossos para fora da casa, e disser ao que estiver no mais interior da casa: Está ainda alguém contigo? e este responder: Ninguém; então lhe dirá ele: Cala-te, porque não devemos fazer menção do nome do Senhor.' },
      { v: 11, en: '“For, behold, Yahweh commands, and the great house will be smashed to pieces, and the little house into bits.', pt: 'Pois eis que o Senhor ordena, e a casa grande será despedaçada, e a casa pequena reduzida a fragmentos.' },
      { v: 12, en: 'Do horses run on the rocky crags? Does one plow there with oxen? But you have turned justice into poison, and the fruit of righteousness into bitterness;', pt: 'Acaso correrão cavalos pelos rochedos? Lavrar-se-á ali com bois? Mas vós haveis tornado o juízo em fel, e o fruto da justiça em alosna;' },
      { v: 13, en: 'you who rejoice in a thing of nothing, who say, ‘Haven’t we taken for ourselves horns by our own strength?’', pt: 'vós que vos alegrais de nada, vós que dizeis: Não nos temos nós tornado poderosos por nossa própria força?' },
      { v: 14, en: 'For, behold, I will raise up against you a nation, house of Israel,” says Yahweh, the God of Armies; “and they will afflict you from the entrance of Hamath to the brook of the Arabah.”', pt: 'Pois eis que eu levantarei contra vós, ó casa de Israel, uma nação, diz o Senhor Deus dos exércitos, e ela vos oprimirá, desde a entrada de Hamate até o ribeiro da Arabá.' },
    ],
    7: [
      { v: 1, en: 'Thus the Lord Yahweh showed me: and behold, he formed locusts in the beginning of the shooting up of the latter growth; and behold, it was the latter growth after the king’s harvest.', pt: 'O Senhor Deus assim me fez ver: e eis que ele formava gafanhotos no princípio do rebentar da erva serôdia, e eis que era a erva serôdia depois da segada do rei.' },
      { v: 2, en: 'When they finished eating the grass of the land, then I said, “Lord Yahweh, forgive, I beg you! How could Jacob stand? For he is small.”', pt: 'E quando eles tinham comido completamente a erva da terra, eu disse: Senhor Deus, perdoa, peço-te; como subsistirá Jacó? pois ele é pequeno.' },
      { v: 3, en: 'Yahweh relented concerning this. “It shall not be,” says Yahweh.', pt: 'Então o Senhor se arrependeu disso. Não acontecerá, disse o Senhor.' },
      { v: 4, en: 'Thus the Lord Yahweh showed me and behold, the Lord Yahweh called for judgment by fire; and it dried up the great deep, and would have devoured the land.', pt: 'Assim me mostrou o Senhor Deus: eis que o Senhor Deus ordenava que por meio do fogo se decidisse o pleito; o fogo, pois, consumiu o grande abismo, e também queria consumir a terra.' },
      { v: 5, en: 'Then I said, “Lord Yahweh, stop, I beg you! How could Jacob stand? For he is small.”', pt: 'Então eu disse: Senhor Deus, cessa agora; como subsistirá Jacó? pois ele é pequeno.' },
      { v: 6, en: 'Yahweh relented concerning this. “This also shall not be,” says the Lord Yahweh.', pt: 'Também disso se arrependeu o Senhor. Nem isso acontecerá, disse o Senhor Deus.' },
      { v: 7, en: 'Thus he showed me and behold, the Lord stood beside a wall made by a plumb line, with a plumb line in his hand.', pt: 'Mostrou-me também assim: eis que o senhor estava junto a um muro levantado a prumo, e tinha um prumo na mão.' },
      { v: 8, en: 'Yahweh said to me, “Amos, what do you see?” I said, “A plumb line.” Then the Lord said, “Behold, I will set a plumb line in the middle of my people Israel. I will not again pass by them any more.', pt: 'Perguntou-me o Senhor: Que vês tu, Amós? Respondi: Um prumo. Então disse o Senhor: Eis que eu porei o prumo no meio do meu povo Israel; nunca mais passarei por ele.' },
      { v: 9, en: 'The high places of Isaac will be desolate, the sanctuaries of Israel will be laid waste; and I will rise against the house of Jeroboam with the sword.”', pt: 'Mas os altos de Isaque serão assolados, e destruídos os santuários de Israel; e levantar-me-ei com a espada contra a casa de Jeroboão.' },
      { v: 10, en: 'Then Amaziah the priest of Bethel sent to Jeroboam king of Israel, saying, “Amos has conspired against you in the middle of the house of Israel. The land is not able to bear all his words.', pt: 'Então Amazias, o sacerdote de Betel, mandou dizer a Jeroboão, rei de Israel: Amós tem conspirado contra ti no meio da casa de Israel; a terra não poderá suportar tedas as suas palavras.' },
      { v: 11, en: 'For Amos says, ‘Jeroboam will die by the sword, and Israel shall surely be led away captive out of his land.’”', pt: 'Pois assim diz Amós: Jeroboão morrerá à espada, e Israel certamente será levado cativo para fora da sua terra.' },
      { v: 12, en: 'Amaziah also said to Amos, “You seer, go, flee away into the land of Judah, and there eat bread, and prophesy there:', pt: 'Depois Amazias disse a Amós: Vai-te, ó vidente, foge para a terra de Judá, e ali come o pão, e ali profetiza;' },
      { v: 13, en: 'but don’t prophesy again any more at Bethel; for it is the king’s sanctuary, and it is a royal house!”', pt: 'mas em Betel daqui por diante não profetizarás mais, porque é o santuário do rei, e é templo do reino.' },
      { v: 14, en: 'Then Amos answered Amaziah, “I was no prophet, neither was I a prophet’s son; but I was a herdsman, and a farmer of sycamore figs;', pt: 'E respondeu Amós, e disse a Amazias: Eu não sou profeta, nem filho de profeta, mas boieiro, e cultivador de sicômoros.' },
      { v: 15, en: 'and Yahweh took me from following the flock, and Yahweh said to me, ‘Go, prophesy to my people Israel.’', pt: 'Mas o Senhor me tirou de após o gado, e o Senhor me disse: Vai, profetiza ao meu povo Israel.' },
      { v: 16, en: 'Now therefore listen to Yahweh’s word: ‘You say, Don’t prophesy against Israel, and don’t preach against the house of Isaac.’', pt: 'Agora, pois, ouve a palavra do Senhor: Tu dizes: Não profetizes contra Israel, nem fales contra a casa de Isaque.' },
      { v: 17, en: 'Therefore Yahweh says: ‘Your wife shall be a prostitute in the city, and your sons and your daughters shall fall by the sword, and your land shall be divided by line; and you yourself shall die in a land that is unclean, and Israel shall surely be led away captive out of his land.’”', pt: 'Portanto assim diz o Senhor: Tua mulher se prostituirá na cidade, e teus filhos e tuas filhas cairão à espada, e a tua terra será repartida a cordel; e tu morrerás numa terra imunda, e Israel certamente será levado cativo para fora da sua terra.' },
    ],
    8: [
      { v: 1, en: 'Thus the Lord Yahweh showed me: behold, a basket of summer fruit.', pt: 'O Senhor Deus assim me fez ver: e eis aqui um cesto de frutos do verão.' },
      { v: 2, en: 'He said, “Amos, what do you see?” I said, “A basket of summer fruit.” Then Yahweh said to me, “The end has come on my people Israel. I will not again pass by them any more.', pt: 'E disse: Que vês, Amós? Eu respondi: um cesto de frutos do verão. Então o Senhor me disse: Chegou o fim sobre o meu povo Israel; nunca mais passarei por ele.' },
      { v: 3, en: 'The songs of the temple will be wailings in that day,” says the Lord Yahweh. “The dead bodies will be many. In every place they will throw them out with silence.', pt: 'Mas os cânticos do templo serão gritos de dor naquele dia, diz o Senhor Deus; muitos serão os cadáveres; em todos os lugares serão lançados fora em silêncio.' },
      { v: 4, en: 'Hear this, you who desire to swallow up the needy, and cause the poor of the land to fail,', pt: 'Ouvi isto, vós que pisais os necessitados, e destruís os miseráveis da terra,' },
      { v: 5, en: 'Saying, ‘When will the new moon be gone, that we may sell grain? And the Sabbath, that we may market wheat, making the ephah small, and the shekel large, and dealing falsely with balances of deceit;', pt: 'dizendo: Quando passará a lua nova, para vendermos o grão? e o sábado, para expormos o trigo, diminuindo a medida, e aumentando o preço, e procedendo dolosamente com balanças enganadoras,' },
      { v: 6, en: 'that we may buy the poor for silver, and the needy for a pair of shoes, and sell the sweepings with the wheat?’”', pt: 'para comprarmos os pobres por dinheiro, e os necessitados por um par de sapatos, e para vendermos o refugo do trigo?' },
      { v: 7, en: 'Yahweh has sworn by the pride of Jacob, “Surely I will never forget any of their works.', pt: 'Jurou o Senhor pela glória de Jacó: Certamente nunca me esquecerei de nenhuma das suas obras.' },
      { v: 8, en: 'Won’t the land tremble for this, and everyone mourn who dwells in it? Yes, it will rise up wholly like the River; and it will be stirred up and sink again, like the River of Egypt.', pt: 'Por causa disso não estremecerá a terra? e não chorará todo aquele que nela habita? Certamente se levantará ela toda como o Nilo, e será agitada, e diminuirá como o Nilo do Egito.' },
      { v: 9, en: 'It will happen in that day,” says the Lord Yahweh, “that I will cause the sun to go down at noon, and I will darken the earth in the clear day.', pt: 'E sucederá, naquele dia, diz o Senhor Deus, que farei que o sol se ponha ao meio dia, e em pleno dia cobrirei a terra de trevas.' },
      { v: 10, en: 'I will turn your feasts into mourning, and all your songs into lamentation; and I will make you wear sackcloth on all your bodies, and baldness on every head. I will make it like the mourning for an only son, and its end like a bitter day.', pt: 'E tornarei as vossas festas em luto, e todos os vossos cânticos em lamentações; porei saco sobre todos os lombos, e calva sobre toda cabeça; e farei que isso seja como o luto por um filho único, e o seu fim como dia de amarguras.' },
      { v: 11, en: 'Behold, the days come,” says the Lord Yahweh, “that I will send a famine in the land, not a famine of bread, nor a thirst for water, but of hearing Yahweh’s words.', pt: 'Eis que vêm os dias, diz o Senhor Deus, em que enviarei fome sobre a terra; não fome de pão, nem sede de água, mas de ouvir as palavras do Senhor.' },
      { v: 12, en: 'They will wander from sea to sea, and from the north even to the east; they will run back and forth to seek Yahweh’s word, and will not find it.', pt: 'Andarão errantes de mar a mar, e do norte até o oriente; correrão por toda parte, buscando a palavra do Senhor, e não a acharão.' },
      { v: 13, en: 'In that day the beautiful virgins and the young men will faint for thirst.', pt: 'Naquele dia as virgens formosas e os mancebos desmaiarão de sede.' },
      { v: 14, en: 'Those who swear by the sin of Samaria, and say, ‘As your god, Dan, lives;’ and, ‘As the way of Beersheba lives;’ they will fall, and never rise up again.”', pt: 'Os que juram pelo pecado de Samária, dizendo: Pela vida do teu deus, ó Dã; e: Pelo caminho de Berseba; esses mesmos cairão, e não se levantarão mais.' },
    ],
    9: [
      { v: 1, en: 'I saw the Lord standing beside the altar, and he said, “Strike the tops of the pillars, that the thresholds may shake; and break them in pieces on the head of all of them; and I will kill the last of them with the sword: there shall not one of them flee away, and there shall not one of them escape.', pt: 'Vi o Senhor, que estava junto ao altar; e me disse: Fere os capitéis, para que estremeçam os umbrais; e faze tudo em pedaços sobre a cabeça de todos eles; e eu matarei à espada até o último deles; nenhum deles conseguirá fugir, nenhum deles escapará.' },
      { v: 2, en: 'Though they dig into Sheol, there my hand will take them; and though they climb up to heaven, there I will bring them down.', pt: 'Ainda que cavem até o Seol, dali os tirará a minha mão; ainda que subam ao céu, dali os farei descer.' },
      { v: 3, en: 'Though they hide themselves in the top of Carmel, I will search and take them out there; and though they be hidden from my sight in the bottom of the sea, there I will command the serpent, and it will bite them.', pt: 'Ainda que se escondam no cume do Carmelo, buscá-los-ei, e dali os tirarei; e, ainda que se ocultem aos meus olhos no fundo do mar, ali darei ordem à serpente, e ela os morderá.' },
      { v: 4, en: 'Though they go into captivity before their enemies, there I will command the sword, and it will kill them. I will set my eyes on them for evil, and not for good.', pt: 'Também ainda que vão para o cativeiro diante de seus inimigos, ali darei ordem à espada, e ela os matará; enfim eu porei os meus olhos sobre eles para o mal, e não pera o bem.' },
      { v: 5, en: 'For the Lord, Yahweh of Armies, is he who touches the land and it melts, and all who dwell in it will mourn; and it will rise up wholly like the River, and will sink again, like the River of Egypt.', pt: 'Pois o Senhor, o Deus dos exércitos, é o que toca a terra, e ela se derrete, e pranteiam todos os que nela habitam; e ela toda se levanta como o Nilo, e diminui como o Nilo do Egito.' },
      { v: 6, en: 'It is he who builds his rooms in the heavens, and has founded his vault on the earth; he who calls for the waters of the sea, and pours them out on the surface of the earth; Yahweh is his name.', pt: 'Ele é o que edifica as suas câmaras no céu, e funda sobre a terra a sua abóbada; que chama as águas do mar, e as derrama sobre a terra; o Senhor é o seu nome.' },
      { v: 7, en: 'Are you not like the children of the Ethiopians to me, children of Israel?” says Yahweh. “Haven’t I brought up Israel out of the land of Egypt, and the Philistines from Caphtor, and the Syrians from Kir?', pt: 'Não sois vós para comigo, ó filhos de Israel, como os filhos dos etíopes? diz o Senhor; não fiz eu subir a Israel da terra do Egito, e aos filisteus de Caftor, e aos sírios de Quir?' },
      { v: 8, en: 'Behold, the eyes of the Lord Yahweh are on the sinful kingdom, and I will destroy it from off the surface of the earth; except that I will not utterly destroy the house of Jacob,” says Yahweh.', pt: 'Eis que os olhos do Senhor Deus estão contra este reino pecador, e eu o destruirei de sobre a face da terra; contudo não destruirei de todo a casa de Jacó, diz o Senhor.' },
      { v: 9, en: '“For, behold, I will command, and I will sift the house of Israel among all the nations, as grain is sifted in a sieve, yet not the least kernel will fall on the earth.', pt: 'Pois eis que darei ordens, e sacudirei a casa de Israel em todas as nações, assim como se sacode grão no crivo; todavia não cairá sobre a terra um só grão.' },
      { v: 10, en: 'All the sinners of my people will die by the sword, who say, ‘Evil won’t overtake nor meet us.’', pt: 'Morrerão à espada todos os pecadores do meu povo, os quais dizem: O mal não nos alcançará, nem nos encontrará.' },
      { v: 11, en: 'In that day I will raise up the tent of David who is fallen, and close up its breaches, and I will raise up its ruins, and I will build it as in the days of old;', pt: 'Naquele dia tornarei a levantar o tabernáculo de Davi, que está caído, e repararei as suas brechas, e tornarei a levantar as suas ruínas, e as reedificarei como nos dias antigos;' },
      { v: 12, en: 'that they may possess the remnant of Edom, and all the nations who are called by my name,” says Yahweh who does this.', pt: 'para que eles possuam o resto de Edom, e todas as nações que são chamadas pelo meu nome, diz o Senhor, que faz estas coisas.' },
      { v: 13, en: '“Behold, the days come,” says Yahweh, “that the plowman shall overtake the reaper, and the one treading grapes him who sows seed; and sweet wine will drip from the mountains, and flow from the hills.', pt: 'Eis que vêm os dias, diz o Senhor, em que o que lavra alcançará ao que sega, e o que pisa as uvas ao que lança a semente; :e os montes destilarão mosto, e todos os outeiros se derreterão.' },
      { v: 14, en: 'I will bring my people Israel back from captivity, and they will rebuild the ruined cities, and inhabit them; and they will plant vineyards, and drink wine from them. They shall also make gardens, and eat their fruit.', pt: 'Também trarei do cativeiro o meu povo Israel; e eles reedificarão as cidades assoladas, e nelas habitarão; plantarão vinhas, e beberão o seu vinho; e farão pomares, e lhes comerão o fruto.' },
      { v: 15, en: 'I will plant them on their land, and they will no more be plucked up out of their land which I have given them,” says Yahweh your God.', pt: 'Assim os plantarei na sua terra, e não serão mais arrancados da sua terra que lhes dei, diz o senhor teu Deus.' },
    ],
  },
};

export default book;
